#!/bin/shset -euo pipefailCORE_NAME="cl_0"CONFIG_DIR="/opt/solr/server/solr/configsets/$CORE_NAME"echo "=== Initializing Solr core: $CORE_NAME ==="# Only copy if not already presentif [ ! -d "$CONFIG_DIR" ]; then  echo "Copying _default configset to $CORE_NAME ..."  cp -R /opt/solr/server/solr/configsets/_default "$CONFIG_DIR"    echo "Patching solrconfig.xml ..."  sed -i '/<\/config>/i \<requestHandler name="/lireq" class="org.apache.solr.handler.component.SearchHandler">\  <lst name="defaults">\    <str name="wt">json</str>\    <str name="indent">true</str>\  </lst>\  <lst name="invariants">\    <arr name="contentType">\      <str>image/jpeg</str>\      <str>image/png</str>\    </arr>\  </lst>\</requestHandler>' "$CONFIG_DIR/conf/solrconfig.xml"else  echo "Configset $CORE_NAME already exists, skipping copy."fi